return ['domain'=>'agnosis','plural-forms'=>'nplurals=1; plural=0;','language'=>'zh_CN','project-id-version'=>'Agnosis 0.9.21','pot-creation-date'=>'2026-07-12T16:27+00:00','po-revision-date'=>'2026-07-12 18:28+0000','x-generator'=>'Loco https://localise.biz/','messages'=>['Agnosis'=>'Agnosis','https://agnosis.art'=>'https://agnosis.art','Art blooming out of oblivion. Email your art, AI polishes it, the world sees it. A free, federated publishing network for independent artists.'=>'从遗忘中绽放的艺术。把你的作品发到邮箱，AI 为它润色，世界便能看见。一个面向独立艺术家的免费、去中心化发布网络。','Agnosis Network'=>'Agnosis 网络','Agnosis requires PHP %s or higher.'=>'Agnosis 需要 PHP %s 或更高版本。','Agnosis requires WordPress %s or higher.'=>'Agnosis 需要 WordPress %s 或更高版本。','Filter by medium'=>'按媒介筛选','All'=>'全部','Enlarged image'=>'放大后的图片','Featured'=>'精选','Enlarge'=>'放大','Gallery pages'=>'画廊页面','Prev'=>'上一页','Next'=>'下一页','Contact Messages'=>'联系消息','No contact messages yet.'=>'还没有联系消息。','No messages match this filter.'=>'没有消息符合此筛选条件。','#'=>'#','Artist'=>'艺术家','From'=>'来自','Message'=>'消息','Status'=>'状态','Received'=>'接收时间','Actions'=>'操作','(deleted artist #%d)'=>'（已删除的艺术家 #%d）','You do not have permission to perform this action.'=>'你没有权限执行此操作。','Message deleted.'=>'消息已删除。','All statuses'=>'所有状态','Sent'=>'已发送','Rejected'=>'已拒绝','Filter'=>'筛选','Reset'=>'重置','Page %1$d of %2$d'=>'第 %1$d 页，共 %2$d 页','Previous'=>'上一页','Delete this message?'=>'删除这条消息？','Delete'=>'删除','just now'=>'刚刚','%dm ago'=>'%d 分钟前','%dh ago'=>'%d 小时前','Mail from (workflow)'=>'Mail from (workflow)','Newsletter'=>'通讯订阅','Agnosis Inbox'=>'Agnosis 收件箱','Inbox'=>'收件箱','No messages in the queue yet. Click "Poll Inbox" to fetch messages from your IMAP account.'=>'当前队列中还没有消息。点击“轮询收件箱”从你的 IMAP 账户获取消息。','No queue rows match this filter.'=>'没有队列行符合此筛选条件。','Subject'=>'主题','Endpoint'=>'端点','Files'=>'文件','Error'=>'错误','unregistered sender'=>'未注册的发送者','Old row — delete and re-poll to preview'=>'旧行 — 删除并重新轮询以预览','Attachment viewer'=>'附件查看器','Close'=>'关闭','Queue row deleted. Poll Inbox to re-fetch the message.'=>'队列行已删除。请轮询收件箱以重新获取消息。','Queue #%d sent to pipeline. Check back in a few seconds.'=>'队列 #%d 已发送到流水线。请几秒后回来查看。','Poll complete. %d new message(s) added to the queue.'=>'轮询完成。已将 %d 条新消息添加到队列。','Force-reprocess: %1$d row(s) reset, %2$d new message(s) enqueued.'=>'强制重新处理：已重置 %1$d 行，已新增 %2$d 条消息。','Processed %d pending item(s).'=>'已处理 %d 个待处理项目。','Pending'=>'待处理','Processing'=>'处理中','Published'=>'已发布','Failed'=>'失败','Skipped'=>'已跳过','All reasons'=>'所有原因','%1$d message from an unregistered sender is hidden from this view. <a href="%2$s">View it</a>.'=>'来自未注册发送者的 %1$d 条消息已在此视图中隐藏。<a href="%2$s">查看</a>。','Poll Inbox'=>'轮询收件箱','Force Reprocess'=>'强制重新处理','Process All Pending'=>'处理所有待处理项','Goodbye'=>'再见','Community'=>'社区','Bounce'=>'弹回','Awaiting Review'=>'待审核','Live'=>'上线','Processed'=>'已处理','Member Removed'=>'成员已移除','Broadcast Sent'=>'已发送广播','Bounced (too long)'=>'退信（太长）','Handled'=>'已处理','Process'=>'处理','View Post'=>'查看帖子','Reprocess'=>'重新处理','Running…'=>'运行中…','Delete this queue row?'=>'要删除此队列行吗？','Configuration'=>'配置','Force-reprocess complete. %1$d queue row(s) reset, %2$d new message(s) enqueued. Click "Process Pending Queue" to run the AI pipeline.'=>'强制重新处理完成。已重置 %1$d 个队列行，已新增 %2$d 条消息。点击“处理待处理队列”运行 AI 流水线。','Log cleared.'=>'日志已清除。','Debug files cleared. %d file was removed.'=>'调试文件已清除。已删除 %d 个文件。','Term translation cache cleared. Terms will be re-translated the next time they\'re needed.'=>'词条翻译缓存已清除。下次需要这些词条时将重新翻译。','Processed %d pending queue item(s). Check the Logs tab for details.'=>'已处理 %d 个待处理队列项。详情请查看“日志”标签页。','Poll complete. %d new message(s) enqueued. Check the Logs tab, then click Process Pending Queue.'=>'轮询完成。已新增 %d 条消息到队列。详情请查看“日志”标签页，然后点击“处理待处理队列”。','Applicant admitted. A welcome email has been sent.'=>'申请人已录取。欢迎邮件已发送。','Could not admit — the application may no longer be pending.'=>'无法录取——该申请可能已不再处于待处理状态。','Application rejected.'=>'申请已拒绝。','Could not reject — the application may no longer be pending.'=>'无法拒绝——该申请可能已不再处于待处理状态。','Artist suspended. A notification email has been sent.'=>'艺术家已暂停。通知邮件已发送。','Could not suspend the artist — they may no longer be active.'=>'无法暂停该艺术家——他们可能已不再处于活跃状态。','Artist permanently deleted. Their account and all content have been removed.'=>'艺术家已永久删除。其账户及全部内容均已移除。','Could not delete the artist — please try again.'=>'无法删除该艺术家——请重试。','Community removal vote opened. All artists have been emailed.'=>'社区移除投票已开启。所有艺术家均已收到邮件。','Could not open a removal vote — one may already be active for this artist.'=>'无法开启移除投票——该艺术家可能已有一个投票正在进行中。','Issue prepared and queued — it will go out over the next few cron cycles.'=>'期刊已准备并入队——它将在接下来的几个 cron 周期内发出。','Could not start this issue — a previous one may still be sending.'=>'无法开始处理此项问题——之前的一项可能仍在发送中。','Test email sent — check the inbox you sent it to.'=>'测试邮件已发送——请查看你发送到的收件箱。','Could not send the test email — check the address and your site\'s outgoing mail configuration.'=>'无法发送测试邮件——请检查地址以及你网站的外发邮件配置。','Invitation sent.'=>'邀请已发送。','Could not send the invitation — check the address and your site\'s outgoing mail configuration.'=>'无法发送邀请——请检查地址以及你网站的外发邮件配置。','Test invitation sent — check the inbox you sent it to.'=>'测试邀请已发送——请查看你发送到的收件箱。','Could not send the test invitation — check the address and your site\'s outgoing mail configuration.'=>'无法发送测试邀请——请检查地址以及你网站的外发邮件配置。','Test email sent — check whether it lands in your inbox or your spam folder.'=>'测试邮件已发送——请检查它是否进入你的收件箱或垃圾邮件文件夹。','Failed recipients reset to pending — they will be retried on the next few cron cycles.'=>'失败的收件人已重置为待处理——它们将在接下来的几次 cron 周期中重试。','No failed recipients to retry for this newsletter.'=>'此通讯没有需要重试的失败收件人。','Art blooming out of oblivion'=>'让艺术从遗忘中绽放','Save Changes'=>'保存更改','Members'=>'成员','Rules'=>'规则','General'=>'常规','Email Inbox'=>'邮件收件箱','AI Providers'=>'AI 提供方','Behavior'=>'行为','Network'=>'网络','Commerce'=>'商店','Logs'=>'日志','— None (inline message only) —'=>'— 无（仅内联消息） —','Reset to default'=>'恢复为默认值','Replaces the text above with the plugin\'s built-in default — click Save Changes below to keep it.'=>'用插件内置的默认文本替换上方文本——点击下方“保存更改”以保留它。','Select Image'=>'选择图片','Remove'=>'移除','Base domain'=>'基础域名','Root domain for artist subdomains, e.g. agnosis.art. Each artist is reachable at nicename.{base_domain}. Requires a wildcard DNS record (*.{base_domain}) pointing to this server. Leave blank to disable subdomain routing.'=>'艺术家子域名的根域名，例如 agnosis.art。每位艺术家都可通过 nicename.{base_domain} 访问。需要一条指向此服务器的通配 DNS 记录（*.{base_domain}）。留空可禁用子域名路由。','Debug logging'=>'调试日志','Writes raw diagnostic dumps of the email intake pipeline (message structure, attachment MIME detection, media conversion, post creation) to a dedicated debug directory — far more detail than the Logs tab keeps, for tracing exactly where a submission was rejected or lost. Turn off once you have what you need; files can accumulate quickly. Can also be forced from wp-config.php with `define( \'AGNOSIS_DEBUG\', true );`, which overrides this toggle. See the Debug Files panel below for the directory location and a clear-files button.'=>'将邮件接入流程的原始诊断转储（消息结构、附件 MIME 检测、媒体转换、文章创建）写入专用调试目录——比日志选项卡保留的细节更多得多，用于精确追踪提交是在何处被拒绝或丢失的。在获得所需信息后请关闭；文件可能会很快累积。也可以在 wp-config.php 中通过 `define( \'AGNOSIS_DEBUG\', true );` 强制启用，这会覆盖此开关。请参见下方“调试文件”面板以查看目录位置和清空文件按钮。','Debug file retention (days)'=>'调试文件保留时间（天）','Debug dumps older than this are permanently deleted by the daily cleanup — automatically, whether or not debug logging is currently turned on, so files left over from a past debug session don\'t linger indefinitely. A dump is a full raw copy of an artist\'s email, so this defaults shorter than the inbox/queue retention above. Default: 14 days.'=>'超过此时间的调试转储会在每日清理中被永久删除——无论调试日志当前是否开启，都会自动执行，因此过去调试会话留下的文件不会无限期保留。转储是艺术家邮件的完整原始副本，因此默认保留时间短于上方的收件箱/队列保留时间。默认：14 天。','Email logo'=>'邮件徽标','Shown in the header of outgoing HTML emails (submission review, removal confirmation, rejection notice, and both newsletters) in place of the plain "✦ Site Name" text. Leave empty to keep the text wordmark. Displayed at up to 40px tall — any width or aspect ratio works.'=>'显示在外发 HTML 邮件的页眉中（提交审核、移除确认、拒绝通知，以及两种通讯邮件）以替代纯文本“✦ 站点名称”。留空则保留文本标识。显示高度最高 40px——宽度或宽高比不限。','Preset biography title'=>'预设简介标题','When set, every artist\'s biography page uses this exact title instead of their own, regardless of what the artist submitted, edited on their approve form, or later changed on their published page. Leave blank to keep using each artist\'s own title (the default). Shown exactly as typed here on every language version of a biography page — not machine-translated per language. See "Include artist\'s name in preset title" below.'=>'启用后，每位艺术家的简介页面都将使用此确切标题，而不是他们自己的标题，无论艺术家提交了什么、在审批表单中编辑了什么，或之后在已发布页面上更改了什么。留空则继续使用每位艺术家自己的标题（默认）。在简介页面的每种语言版本中都会按此处输入的原样显示——不会按语言自动翻译。另请参见下方“在预设标题中包含艺术家姓名”。','Include artist\'s name in preset title'=>'在预设标题中包含艺术家姓名','When the preset title above is set, append the artist\'s own WordPress display name to it (e.g. "Meet the Artist — Jane Doe"). Has no effect while the preset title is blank.'=>'当上方的预设标题已设置时，会在其后附加艺术家自己的 WordPress 显示名称（例如：“认识这位艺术家 — Jane Doe”）。若预设标题为空，则无效。','Cloudflare Turnstile site key'=>'Cloudflare Turnstile 站点密钥','From your Cloudflare Turnstile widget (dash.cloudflare.com → Turnstile). Adds a human-verification check to the public Subscribe (newsletter-signup) and Join forms. Leave either key blank to leave both forms exactly as they are today.'=>'来自你的 Cloudflare Turnstile 小组件（dash.cloudflare.com → Turnstile）。为公开的“订阅”（newsletter-signup）和“加入”表单添加人工验证检查。留空任一密钥即可使这两个表单保持当前状态。','Cloudflare Turnstile secret key'=>'Cloudflare Turnstile 密钥','Kept server-side only — used to verify each form submission directly with Cloudflare before it is accepted.'=>'仅保留在服务器端——用于在接受每次表单提交之前，直接与 Cloudflare 验证。','Email driver'=>'邮件驱动','Artwork submissions address'=>'作品提交地址','Artists send artwork to this address — e.g. submit@agnosis.art'=>'艺术家将作品发送到此地址——例如 submit@agnosis.art','Biography submissions address'=>'简介提交地址','Artists send biography updates to this address — e.g. bio@agnosis.art'=>'艺术家将简介更新发送到此地址——例如 bio@agnosis.art','Event submissions address'=>'活动提交地址','Artists send event announcements to this address — e.g. event@agnosis.art'=>'艺术家将活动公告发送到此地址——例如 event@agnosis.art','Replace artwork address'=>'替换作品地址','Artist sends a new version of an existing artwork. Subject must match the original title. Bypasses duplicate detection — e.g. replace@agnosis.art'=>'艺术家发送现有作品的新版本。主题必须与原始标题一致。绕过重复检测——例如：replace@agnosis.art','Removal request address'=>'移除请求地址','Artist requests takedown of an existing artwork. Subject must match the title. Moves the post to draft pending admin review — e.g. remove@agnosis.art'=>'艺术家请求下架现有作品。主题必须与标题一致。将帖子移至草稿，等待管理员审核——例如：remove@agnosis.art','Promote artwork address'=>'推广作品地址','Artist sends an email here (subject = exact artwork title) to choose which artwork represents them in the shared community gallery on the main site — not their own subdomain, which already shows everything they\'ve published. Any previously featured artwork is automatically demoted — e.g. promote@agnosis.art'=>'艺术家向这里发送电子邮件（主题 = 作品的准确标题），以选择哪件作品代表他们出现在主站点的共享社区画廊中——不是他们自己的子域名，后者已经展示了他们发布的全部内容。任何先前入选展示的作品都会自动降级——例如：promote@agnosis.art','Photo-only address'=>'仅照片地址','Opt-out lane for photographers and lens-based artists whose photograph is the artwork, not a snapshot of it. Submissions here are published with the original image exactly as sent — AI enhancement is skipped and the quality-rejection gate is bypassed. AI description (title, tags, alt text) still runs. Use the [Photo] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. photo@agnosis.art'=>'为摄影师和以镜头为基础的艺术家提供的退出通道：这里的照片就是作品本身，而不是作品的快照。提交到这里的内容会按原样使用原始图像发布——会跳过 AI 增强，并绕过质量拒绝门槛。AI 描述（标题、标签、替代文本）仍会运行。若邮件客户端不支持 To: 别名，请使用 [Photo] 主题标识作为备用——例如：photo@agnosis.art','Pure address (no AI at all)'=>'纯净地址（完全不使用 AI）','Strictest opt-out lane: nothing sent here is touched by AI — no enhancement, no vision description, no rewriting. The published post title, body, and translated-title subtitle are taken verbatim from the artist\'s own subject and message text; the attached file(s) are published exactly as sent. The quality-rejection gate is bypassed, same as Photo-only. Use the [Pure] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. pure@agnosis.art'=>'最严格的退出通道：发送到这里的内容不会被 AI 处理——不增强、不进行视觉描述、不重写。发布后的帖子标题、正文和翻译后的标题副标题将直接采用艺术家自己的主题和消息文本；附件会按原样发布。质量拒绝门槛会被绕过，与仅照片模式相同。若邮件客户端不支持 To: 别名，请使用 [Pure] 主题标识作为备用——例如：pure@agnosis.art','Goodbye / self-removal address'=>'告别 / 自我移除地址','Artist emails here (any subject, no attachment needed) to request account deletion. A confirmation link is emailed back before anything is deleted — e.g. goodbye@agnosis.art'=>'艺术家向这里发送电子邮件（任意主题，无需附件）以请求删除账户。删除前会先通过电子邮件发送确认链接——例如：goodbye@agnosis.art','Community announcement address'=>'社区公告地址','Any active artist emails here (any subject, no attachment needed) to send a message to every other community member — e.g. community@agnosis.art. Never processed as a submission and never becomes a post: each recipient gets the subject and message translated into their own language, with the sender\'s name and email included so they can reply directly. Sent from the address configured under Settings → Community → Rules, which can be different from this one. Only works for a message sent by an active, admitted artist.'=>'任何活跃艺术家都可以向这里发送电子邮件（任意主题，无需附件），向社区中的其他所有成员发送消息——例如：community@agnosis.art。此邮件绝不会被当作提交内容处理，也永远不会变成帖子：每位收件人都会收到已翻译成其自身语言的主题和消息，并包含发送者姓名和电子邮件，以便他们可以直接回复。邮件从 Settings → Community → Rules 中配置的地址发出，该地址可以与此地址不同。仅适用于由已通过审核并处于活跃状态的艺术家发送的消息。','IMAP host'=>'IMAP 主机','e.g. imap.yourhost.com'=>'例如：imap.yourhost.com','IMAP port'=>'IMAP 端口','Use SSL'=>'使用 SSL','Skip SSL certificate validation'=>'跳过 SSL 证书验证','⚠ Use only as a temporary workaround when your mail server\'s certificate is not yet trusted (e.g. Plesk self-signed cert before Let\'s Encrypt is applied to the mail daemon). Disable this once the mail server presents a valid certificate.'=>'⚠ 仅在邮件服务器的证书尚未被信任时作为临时变通方案使用（例如：在 Let’s Encrypt 应用于邮件守护进程之前，Plesk 使用自签名证书）。一旦邮件服务器提供有效证书，请关闭此项。','IMAP username'=>'IMAP 用户名','Login username for the IMAP account — typically the catch-all mailbox address.'=>'IMAP 账户的登录用户名——通常是收件箱的通用邮箱地址。','Submission email password'=>'提交邮件密码','Webhook secret'=>'Webhook 密钥','HMAC secret shared with your webhook provider (Mailgun, SendGrid…). Used for both the inbound-mail endpoint (/wp-json/agnosis/v1/email/inbound) and the bounce/complaint events endpoint (/wp-json/agnosis/v1/email/events) — point your provider\'s bounce/spam-complaint webhook at the latter to keep your subscriber and artist addresses clean.'=>'与您的 webhook 提供商（Mailgun、SendGrid…）共享的 HMAC 密钥。用于入站邮件端点（/wp-json/agnosis/v1/email/inbound）以及退信/投诉事件端点（/wp-json/agnosis/v1/email/events）——请将提供商的退信/垃圾邮件投诉 webhook 指向后者，以保持订阅者和艺术家的地址清洁。','Inbox retention (days)'=>'收件箱保留期（天）','Seen IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup. Default: 7 days.'=>'已读 IMAP 消息以及已处理/失败队列中早于此时间的行将由每日清理任务永久删除。默认值：7 天。','Contact message retention (days)'=>'联系消息保留期（天）','Visitor-to-artist contact messages (sent or rejected) older than this are permanently deleted by the daily cleanup. The visitor\'s IP address is cleared independently after 30 days regardless of this setting, once it\'s no longer useful for abuse investigation. Default: 90 days.'=>'访客到艺术家的联系消息（已发送或已拒绝）早于此时间的将由每日清理任务永久删除。无论此设置如何，访客的 IP 地址会在 30 天后单独清除，届时它已不再有助于滥用调查。默认值：90 天。','Per-sender hourly submission limit'=>'每个发送者每小时提交上限','Maximum submissions accepted from a single artist per hour, across both IMAP and webhook intake. Exceeding this limit silently drops the message (no retry from ESPs). Default: 5.'=>'单个艺术家每小时可接受的最大提交数，适用于 IMAP 和 webhook 两种接入方式。超过此限制的消息会被静默丢弃（ESP 不会重试）。默认值：5。','Per-artist contact limit'=>'每位艺术家的联系上限','Maximum messages the same visitor (by email address) can send to a single artist within the window below — applies across every language version of that artist\'s page. Default: 2.'=>'同一访客（按电子邮件地址识别）在下方窗口内可以向同一位艺术家发送的最大消息数——适用于该艺术家页面的所有语言版本。默认值：2。','Per-artist contact limit window (hours)'=>'每位艺术家的联系上限窗口（小时）','Time window, in hours, the per-artist contact limit above applies over. Also controls how long a visitor sees the "already contacted" notice instead of the form after messaging an artist. Default: 1 (one hour).'=>'上述每位艺术家的联系上限所适用的时间窗口（按小时计）。同时也控制访客在联系艺术家后，看到“已联系过”提示而不是表单的时长。默认值：1（1 小时）。','Require SPF/DKIM authentication'=>'要求 SPF/DKIM 身份验证','When enabled, intake messages must pass SPF or DKIM authentication (via the Authentication-Results header). Prevents spoofed From: addresses. Requires your ESP to include Authentication-Results headers and your domain to have SPF/DKIM records configured. Leave off if you are not sure — rejected legitimate mail is silent. Default: off.'=>'启用后，接入消息必须通过 SPF 或 DKIM 身份验证（通过 Authentication-Results 头）。可防止伪造 From: 地址。要求您的 ESP 包含 Authentication-Results 头，并且您的域已配置 SPF/DKIM 记录。如果不确定，请保持关闭——被拒绝的合法邮件不会有提示。默认值：关闭。','Description provider'=>'描述提供方','Analyzes the artwork image and writes the title, body, tags and alt text. WordPress AI Services delegates to whichever provider the site has configured via the AI Services plugin.'=>'分析作品图像，并撰写标题、正文、标签和替代文本。WordPress AI Services 会将其委托给站点通过 AI Services 插件配置的提供方。','OpenAI vision model'=>'OpenAI 视觉模型','Model used for artwork description when OpenAI is the description provider. Must support vision input.'=>'当 OpenAI 作为描述提供方时，用于作品描述的模型。必须支持视觉输入。','Anthropic model'=>'Anthropic 模型','Model used for artwork description when Anthropic is the description provider. Must support vision input.'=>'当 Anthropic 作为描述提供方时，用于作品描述的模型。必须支持视觉输入。','Vision image max width (px)'=>'视觉图像最大宽度（像素）','Images are downscaled proportionally to this width before being sent to the AI for description — vision token cost scales with resolution, and a description task needs far fewer pixels than the original photo. Applies to artwork photo uploads, rasterised PDF pages, and video poster frames alike. Set to 0 to always send full-resolution images (uses more tokens, no quality difference for typical description tasks). Requires the Imagick PHP extension; images are sent at their original size regardless of this setting when it is unavailable. Default: 800.'=>'在发送给 AI 进行描述之前，图像会按比例缩小到此宽度——视觉 token 成本会随分辨率增长，而描述任务所需的像素远少于原始照片。适用于作品照片上传、栅格化的 PDF 页面以及视频封面帧。设为 0 可始终发送全分辨率图像（会消耗更多 token，但对典型描述任务没有质量差异）。需要 Imagick PHP 扩展；当该扩展不可用时，图像会以其原始尺寸发送，不受此设置影响。默认值：800。','Enhancement provider'=>'增强服务提供方','Auto (OpenAI if key is set)'=>'自动（如已设置密钥则使用 OpenAI）','Disabled — use original image'=>'已禁用 — 使用原始图像','Enhances the artwork image before publishing. Uses OpenAI gpt-image-1. Set to Disabled to skip enhancement and publish the original.'=>'在发布之前增强作品图像。使用 OpenAI gpt-image-1。设为“已禁用”可跳过增强并发布原始图像。','OpenAI image model'=>'OpenAI 图像模型','Model used for image enhancement when OpenAI is the enhancement provider.'=>'当 OpenAI 为增强服务提供方时，用于图像增强的模型。','Polish biography with AI'=>'使用 AI 润色简介','When enabled, biography submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'启用后，简介提交内容会先通过 AI 进行拼写修正和少量文本优化，然后再保存。','Polish events with AI'=>'使用 AI 润色活动','When enabled, event submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'启用后，活动提交内容会先通过 AI 进行拼写修正和少量文本优化，然后再保存。','Merge biography updates with AI'=>'使用 AI 合并简介更新','When enabled, biography updates are merged with the existing biography using AI — new information is integrated rather than replacing everything. Recommended: artists can send incremental updates ("I just won an award") without resubmitting their full bio. Disable to always replace the biography with the latest submission.'=>'启用后，简介更新会通过 AI 与现有简介合并——新信息会被整合进去，而不是全部替换。推荐：艺术家可以发送增量更新（“我刚获得了一个奖项”），而无需重新提交完整简介。关闭后则始终用最新提交替换简介。','Rejection threshold (quality score)'=>'拒绝阈值（质量评分）','Photos scoring at or below this value (1–10) are automatically rejected — the artist receives a friendly email explaining the issue and is invited to resubmit. Score 0 disables automatic rejection. Must be lower than the enhancement threshold. Default: 3.'=>'评分低于或等于此值（1–10）的照片会被自动拒绝——艺术家会收到一封友好的邮件说明问题，并被邀请重新提交。评分 0 会禁用自动拒绝。必须低于增强阈值。默认值：3。','Enhancement threshold (quality score)'=>'增强阈值（质量评分）','Photos scoring below this value (1–10) are automatically enhanced. Score 10 = perfect photograph, 1 = technically unusable. Default: 7 — only visibly problematic photos are processed. Set to 1 to disable automatic enhancement entirely.'=>'低于此值（1–10）的照片会被自动增强。10 = 完美照片，1 = 技术上不可用。默认值：7——只有明显有问题的照片才会被处理。将其设为 1 可完全禁用自动增强。','OpenAI API key'=>'OpenAI API 密钥','Required when OpenAI is the description or enhancement provider.'=>'当 OpenAI 作为描述或增强提供方时必填。','Anthropic API key'=>'Anthropic API 密钥','Required when Anthropic is the description provider.'=>'当 Anthropic 作为描述提供方时必填。','Artwork display width (px)'=>'作品显示宽度（像素）','Width of the agnosis-artwork image size used in post content and lightbox. Height scales proportionally. Default: 1920. Existing images need to be regenerated after changing this value.'=>'用于帖子内容和灯箱中的 agnosis-artwork 图片尺寸宽度。高度按比例缩放。默认值：1920。更改此值后，现有图片需要重新生成。','Thumbnail size (px)'=>'缩略图尺寸（像素）','Side length of the square agnosis-thumb size used in submission cards and dashboard. Default: 512. Existing images need to be regenerated after changing this value.'=>'用于提交卡片和仪表盘中的 agnosis-thumb 方形尺寸边长。默认值：512。更改此值后，现有图片需要重新生成。','Email image width (px)'=>'邮件图片宽度（像素）','Width of the agnosis-email size used in artist notification emails. Height scales proportionally — no cropping. Default: 420. Existing images need to be regenerated after changing this value.'=>'用于艺术家通知邮件中的 agnosis-email 尺寸宽度。高度按比例缩放——不会裁切。默认值：420。更改此值后，现有图片需要重新生成。','Gallery overview — items per page'=>'画廊概览——每页项目数','How many artwork cards the gallery overview shows per page. Pool is built proportionally across all artists; featured artworks are preferred. Default: 12.'=>'画廊概览每页显示多少个作品卡片。资源池会按所有艺术家的比例构建；优先显示精选作品。默认值：12。','Review link expiry (days)'=>'审阅链接有效期（天）','How long the Approve & Publish / Discard links in a submission review email stay valid before an artist has to log in to manage the item instead. Applies uniformly to artwork, biography, and event drafts. Default: 7.'=>'提交审阅邮件中的“批准并发布 / 丢弃”链接在艺术家需要登录管理该条目之前可保持有效的时长。适用于作品、简介和活动草稿。默认值：7。','System prompt'=>'系统提示词','Sent to the AI as the system instruction. Use {tag_count} and {excerpt_words} as tokens — they are replaced with the values below.'=>'作为系统指令发送给 AI。将 {tag_count} 和 {excerpt_words} 作为占位符使用——它们会被下面的值替换。','Artist prompt template'=>'艺术家提示模板','User message sent alongside the artwork image. Use {artist_prompt} where the artist\'s own description should appear.'=>'与作品图片一同发送的用户消息。请在艺术家自己的描述应出现的位置使用 {artist_prompt}。','Enhancement instructions'=>'增强指令','Instructions passed to the image enhancement provider. The AI-generated artwork description is appended automatically as context.'=>'传递给图片增强提供方的指令。AI 生成的作品描述会自动附加作为上下文。','Number of tags'=>'标签数量','How many tags the AI should generate per artwork. Referenced as {tag_count} in the system prompt.'=>'AI 应为每件作品生成多少个标签。在系统提示词中以 {tag_count} 引用。','Excerpt word limit'=>'摘录字数上限','Maximum words for the one-sentence excerpt. Referenced as {excerpt_words} in the system prompt.'=>'单句摘录的最大字数。在系统提示词中以 {excerpt_words} 引用。','Trust all admitted artists (skip link review entirely)'=>'信任所有已接纳艺术家（完全跳过链接审查）','Every artist here was already vouched in by the community — if that trust is enough for you, turn this on to embed any link an artist submits, immediately, with no allowlist check and no AI review at all (the settings below are skipped entirely while this is on). Off by default. Only enable this if you are comfortable that a bad actor who made it through admission could embed a link to anything.'=>'这里的每位艺术家都已由社区引荐——如果这足以让你放心，可开启此项，让艺术家提交的任何链接都立即以内嵌形式显示，不进行允许名单检查，也完全不进行 AI 审查（开启期间下方设置会被完全跳过）。默认关闭。只有在你能接受通过接纳流程的恶意行为者可能嵌入指向任意内容的链接时，才应启用。','Trusted embed platforms'=>'受信任的嵌入平台','One hostname per line. A submitted link becomes a rich embed immediately if it matches one of these (or a subdomain of one) — no AI review needed, no network request made to the link itself.'=>'每行一个主机名。提交的链接如果匹配其中之一（或其子域名之一），就会立即作为富媒体嵌入显示——无需 AI 审查，也不会对链接本身发起网络请求。','Let artists submit other links too (AI-reviewed)'=>'允许艺术家提交其他链接（由 AI 审查）','When enabled, a link to a site not on the trusted list above is not simply discarded: the destination page is fetched and reviewed by your configured AI provider (Settings → AI Providers) against the categories below before deciding whether to embed it. If the AI cannot be reached, the request times out, or the page cannot be safely fetched, the link is not embedded — it fails safe. When disabled (the default), only the trusted platforms above are ever embedded.'=>'启用后，未在上方受信任列表中的站点链接不会被直接丢弃：在决定是否嵌入之前，会先抓取目标页面，并由你配置的 AI 提供方（设置 → AI 提供方）根据下列类别进行审查。如果 AI 无法访问、请求超时，或页面无法安全抓取，则不会嵌入该链接——会安全失败。禁用时（默认），只会嵌入上方受信任的平台。','Block pornographic / sexually explicit content'=>'屏蔽色情 / 性暗示内容','Only takes effect when AI review (above) is enabled.'=>'仅在启用 AI 审查（上方）时生效。','Block primarily commercial / promotional sites'=>'屏蔽主要以商业 / 促销为主的网站','Online stores, advertising, marketing landing pages. Off by default — an artist linking to a shop selling their own prints is common and not inherently unwanted. Only takes effect when AI review (above) is enabled.'=>'网店、广告、营销落地页。默认关闭——艺术家链接到出售自己版画的商店很常见，也并非本身令人反感。仅在启用 AI 审查（上方）时生效。','Block gambling / betting sites'=>'屏蔽博彩 / 赌博网站','Additional disallowed categories'=>'其他不允许的类别','Optional — describe any other kind of content the AI should reject, in plain language (e.g. "hate speech or violent extremist content", "phishing or scam pages"). Only takes effect when AI review (above) is enabled.'=>'可选——用通俗语言描述你希望 AI 拒绝的其他内容类型（例如“仇恨言论或暴力极端主义内容”、“钓鱼或诈骗页面”）。仅在启用 AI 审查（上方）时生效。','Node label'=>'节点标签','How this node introduces itself to the network.'=>'此节点向网络的自我介绍方式。','Enable ActivityPub federation'=>'启用 ActivityPub 联邦功能','Broadcast new artworks to Mastodon, Pixelfed and the Fediverse.'=>'向 Mastodon、Pixelfed 和 Fediverse 广播新作品。','Node public key'=>'节点公钥','Auto-generated RSA public key for this node. Share this with peer nodes.'=>'此节点自动生成的 RSA 公钥。请将其分享给对等节点。','Sender name'=>'发件人名称','Name shown as the sender of admission, vote, welcome, departure, and other workflow emails. Leave blank to use the site name.'=>'在录取、投票、欢迎、离开及其他工作流邮件中显示为发件人的名称。留空则使用站点名称。','Sender email address'=>'发件人电子邮件地址','Dedicated From: address for admission, vote, welcome, departure, invitation, and submission-review emails — e.g. hello@agnosis.art. Deliberately separate from the Settings → Newsletter sender: these are one-off actions (a vote link, a review link), not digest mail. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'用于录取、投票、欢迎、离开、邀请和投稿审核邮件的专用 From: 地址——例如 hello@agnosis.art。刻意与“设置 → 新闻通讯发件人”分开：这些是一次性操作（投票链接、审核链接），不是摘要邮件。留空则使用管理员邮箱。必须是你域名下一个有效、可送达的地址（已配置 SPF/DKIM），否则邮件可能会被标记为垃圾邮件。','Self-removal (goodbye) requests per sender per day'=>'每位发件人每天的自我移除（告别）请求数','Maximum number of self-removal ("goodbye") confirmation emails a single sender address can trigger per day. A genuine self-removal only ever needs to be requested once — this caps how many confirmation emails a spoofed or repeated From can be used to spam a real artist with. Default: 3.'=>'单个发件人地址每天最多可触发的自我移除（“告别”）确认邮件数量。真正的自我移除通常只需要请求一次——此上限用于防止伪造或重复的 From 被用来向真实艺术家发送垃圾确认邮件。默认值：3。','Community broadcasts per artist per day'=>'每位艺术家每天的社区广播数','Maximum number of messages a single artist can send to the Community announcement address (Settings → Email) per day. Prevents one member from flooding every other member\'s inbox. Default: 3.'=>'单个艺术家每天可发送到社区公告地址（设置 → 电子邮件）的最大消息数。可防止某一成员淹没其他所有成员的收件箱。默认值：3。','Community broadcast max length (characters)'=>'社区广播最大长度（字符）','Longer messages to the Community announcement address are bounced back to the sender instead of being broadcast — the sender is told to shorten it and resend. Measured in characters, not words, so it applies fairly across languages that don\'t use spaces between words (Chinese, Japanese, Thai, etc.). Every recipient\'s copy is translated individually, so this also caps how much a single message can cost in AI translation calls. Default: 2000. Hard maximum: 20000, regardless of this setting.'=>'发送到社区公告地址的较长消息不会被广播，而是退回给发件人——系统会提示其缩短后重新发送。以字符而非单词计量，因此对不使用空格分隔单词的语言（如中文、日文、泰语等）也同样公平。每位收件人的副本都会单独翻译，因此这也限制了一条消息在 AI 翻译调用上的最高成本。默认值：2000。硬性上限：20000，不受此设置影响。','Admission vote threshold (%)'=>'录取投票门槛（%）','Percentage of active artists that must vote yes for admission. Combined with the minimum floor below.'=>'必须获得“赞成”票的活跃艺术家百分比。与下方的最低票数下限结合使用。','Admission minimum votes'=>'录取最低票数','Absolute minimum positive votes required regardless of the percentage above.'=>'无论上面的百分比如何，都必须达到的绝对最低赞成票数。','Voting window (days)'=>'投票窗口（天）','Days an application stays open. If the threshold is not reached within this window the application is rejected.'=>'申请保持开放的天数。如果在此期间未达到门槛，申请将被拒绝。','Resolved application retention (days)'=>'已处理申请保留期（天）','A rejected, withdrawn, or left application\'s email, name, biography, statement, and portfolio link are anonymized by the daily cleanup after this many days — the application record itself (status and dates) is kept for admission history. A banned artist\'s biography/statement/portfolio are anonymized on the same schedule, but their email is deliberately kept so the ban stays enforceable. Default: 180 days.'=>'在每日清理任务执行多少天后，被拒绝、撤回或离开的申请的电子邮件、姓名、简介、声明和作品集链接将被匿名化——申请记录本身（状态和日期）会保留，用于录取历史。被封禁艺术家的简介/声明/作品集也会按相同时间表匿名化，但其电子邮件会被刻意保留，以便封禁仍可执行。默认值：180 天。','After applying, send artists to'=>'申请后将艺术家发送到','Optional — pick a page explaining the vouching process and what happens next. When the application is submitted successfully, the artist is redirected there instead of just seeing an inline confirmation message. Leave as "None" to keep the inline message only.'=>'可选——选择一个页面来说明推荐流程以及接下来会发生什么。申请成功提交后，艺术家会被重定向到那里，而不是只看到一条内联确认消息。留空为“无”即可仅保留内联消息。','Community size cap'=>'社区规模上限','Maximum number of admitted artists. When full, new applications join a waitlist instead of being rejected, and a freed slot admits the next in line. Set to 0 for no cap. The community can also vote to change this.'=>'可接纳艺术家的最大数量。满员后，新申请将进入等待名单而不是被拒绝；一旦有空位，会按顺序接纳下一位。设为 0 表示不设上限。社区也可以投票更改此项。','Cap-change co-signers required'=>'更改上限所需联署人','How many artists must co-sign a proposal to change the community size cap before it opens as a full community vote.'=>'在将社区规模上限的提案提交为正式社区投票之前，需要多少艺术家联署。','Cap-change vote window (days)'=>'更改上限投票窗口（天）','Days a community cap-change vote stays open. A strict majority of active artists voting yes adopts the new cap.'=>'社区上限变更投票保持开放的天数。活跃艺术家中超过半数赞成即可通过新上限。','Removal nominations required'=>'移除提名所需人数','Number of artist nominations needed before a community removal vote opens. Admins can bypass this threshold.'=>'开启社区移除投票前所需的艺术家提名数量。管理员可以绕过此门槛。','Removal vote window (days)'=>'移除投票窗口（天）','Days a community removal vote stays open. A majority (>50%) of active artists must vote yes for removal to proceed.'=>'社区移除投票保持开放的天数。活跃艺术家中多数（>50%）投赞成票，移除才会继续。','Invitation intro'=>'邀请介绍','Agnosis is a small, self-hosted home for artists who\'d rather make work than manage a platform. There\'s no algorithm deciding who sees your art, no portfolio site to maintain, and no account to configure — just your work, published and translated automatically for a global audience.

Being part of the community is simple: Fellow artists vouch for new applicants, and everyone keeps full ownership of what they publish; you can leave at any time and take your work with you.

Once admitted, you submit new work by sending it as an email — no dashboard, no forms and you can update, promote or remove your artwork as well sending an email. You can find more information visiting the agnosis.art website.'=>'Agnosis 是一个小型、自托管的艺术家家园，适合那些更愿意创作而不是管理平台的人。这里没有算法决定谁能看到你的艺术作品，没有需要维护的作品集网站，也没有需要配置的账户——只有你的作品，会被自动发布并翻译给全球受众。

加入社区很简单：其他艺术家为新申请者担保，每个人都保留其发布内容的完整所有权；你可以随时离开，并带走你的作品。

一旦被接纳，你只需通过发送电子邮件来提交新作品——无需仪表盘、无需表单；你也可以通过发送电子邮件来更新、推广或移除你的作品。更多信息可访问 agnosis.art 网站。','Shown near the top of the "Send Invitation" email below (an "Apply to join" link and site name follow automatically — no need to add either here). Two or three short paragraphs is plenty. Standing copy, not cleared after use like the newsletter intros above — translated automatically when an invitation is sent in a language other than the site\'s own.'=>'显示在下方“发送邀请”邮件的顶部附近（“申请加入”链接和站点名称会自动跟随——无需在此添加）。两到三个简短段落即可。这里是固定文案，不会像上面的通讯简介那样在使用后被清除——当邀请以非站点默认语言发送时会自动翻译。','Transaction fee (%)'=>'交易手续费（%）','Percentage retained by this node on donations and art sales. Artists pay nothing up front.'=>'本站点在捐赠和艺术品销售中保留的百分比。艺术家前期无需支付任何费用。','Name shown as the sender of digest emails. Leave blank to use the site name.'=>'显示为摘要邮件发件人的名称。留空则使用站点名称。','Dedicated From: address for both newsletters, e.g. newsletter@agnosis.art — keeps digest mail separate from the site\'s admin email for deliverability and so artists can filter it. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'用于两种通讯邮件的专用 From: 地址，例如 newsletter@agnosis.art——将摘要邮件与站点管理员邮箱分开，以提高送达率并便于艺术家过滤。留空则使用管理员邮箱。必须是你域名下一个有效、可送达的地址（已配置 SPF/DKIM），否则邮件可能会被标记为垃圾邮件。','Auto-draft newsletter intros'=>'自动草拟新闻简报开头','When enabled, Agnosis drafts an intro via AI ahead of each issue (see the lead time below), saves it to that newsletter\'s intro field, and emails you to review it — unless you\'ve already written one for that cycle. Disable to leave both intro fields exactly as you left them, always.'=>'启用后，Agnosis 会在每期发布前通过 AI 起草一段开头（见下方提前时间），将其保存到该新闻简报的开头字段，并给您发送邮件请您审核——除非您已经为该期写好了开头。禁用后，这两个开头字段都将保持为您上次留下的内容，始终如此。','Draft intro this many hours ahead'=>'提前多少小时草拟开头','How long before an issue is due Agnosis proposes an AI-drafted intro. Only takes effect when auto-drafting (above) is enabled. Default: 24.'=>'在期刊到期前多久，Agnosis 会建议一个由 AI 起草的开头。仅在启用上方的自动草拟时生效。默认值：24。','Artist newsletter'=>'艺术家新闻简报','Admitted artists are auto-enrolled (they can unsubscribe from any issue with one click). Community digest: recent activity, new members, open votes.'=>'已获准的艺术家会自动订阅（他们可在任一期内容中一键取消订阅）。社区摘要：近期活动、新成员、开放投票。','Artist newsletter frequency (days)'=>'艺术家新闻简报频率（天）','Default 30 ≈ monthly. A new issue is prepared once this many days have passed since the last one was sent.'=>'默认 30 天，约等于每月一次。从上次发送之后经过这么多天后，会准备新的一期。','Artist newsletter intro'=>'艺术家新闻简报开头','Optional note prepended to the next artist issue only — cleared automatically once that issue is queued. Leave blank to send the auto-digest with no intro. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'仅在下一期艺术家内容前附加的可选说明——一旦该期进入排队状态后会自动清空。留空则发送不带开头的自动摘要。如果留空，Agnosis 会在发送前大约一天，根据最新内容自动草拟一段，并先通过邮件请您审核——您可随时在此填写自己的内容以跳过自动草拟。','Public newsletter'=>'公开通讯','Visitors subscribe via the agnosis/newsletter-signup block (double opt-in). Digest: new artwork and events published since the last issue.'=>'访客通过 agnosis/newsletter-signup 区块订阅（双重确认）。摘要：自上一期以来发布的新作品和活动。','Public newsletter frequency (days)'=>'公开通讯频率（天）','Default 30 ≈ monthly.'=>'默认 30，约为每月一次。','Public newsletter intro'=>'公开通讯导语','Optional note prepended to the next public issue only — cleared automatically once that issue is queued. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'仅会附加到下一期公开内容前的可选说明——一旦该期进入排队，会自动清除。如果留空，Agnosis 会在该期发送前大约一天自动根据最新内容草拟一段，并先发邮件请您审核——如需跳过，随时可在这里自行撰写。','Send batch size'=>'发送批次大小','Recipients emailed per 5-minute cron tick. Lower this if your host throttles outbound mail; raise it for faster delivery on hosts with generous limits.'=>'每 5 分钟 cron 触发时向多少收件人发送邮件。如果您的主机限制外发邮件，请调低；如果主机限制宽松，可调高以加快投递。','Self-hosting comfort threshold'=>'自托管舒适阈值','Advisory only — self-hosted sending keeps working above this count. Once confirmed public subscribers pass it, this page shows a reminder to consider an email service provider (e.g. Brevo\'s free tier) instead.'=>'仅供参考——即使超过此数量，自托管发送仍可继续工作。一旦确认的公开订阅者超过此数，本页面会显示提醒，建议改用邮件服务提供商（例如 Brevo 的免费层）。','Sends a minimal ping ("Reply with the word: ping") using the configured API key.'=>'使用已配置的 API 密钥发送一个最小 ping（“请回复：ping”）。','Sends a minimal ping using the configured API key.'=>'使用已配置的 API 密钥发送一个最小 ping。','WordPress AI Client'=>'WordPress AI 客户端','Checks that wp_ai_client_prompt() is available (WordPress 7.0+) and a text-generation model is configured.'=>'检查 wp_ai_client_prompt() 是否可用（WordPress 7.0+）以及是否已配置文本生成模型。','Test AI Providers'=>'测试 AI 提供商','Test %s'=>'测试 %s','Bot Protection'=>'机器人防护','Turnstile is configured.'=>'Turnstile 已配置。','The Join application form and the Newsletter Subscribe form both require human verification before they accept a submission.'=>'加入申请表和通讯订阅表在接受提交前都需要进行人工验证。','Turnstile is not configured.'=>'Turnstile 未配置。','Your Join application form is public — anyone can submit an application, and a submitted (and confirmed) application still emails every admitted artist and admin. Right now the only thing standing between that form and an automated bot is a fixed 5-submissions-per-minute-per-IP limit, which a distributed bot can work around entirely. Add a Cloudflare Turnstile site key and secret key above to require human verification on both the Join form and the Newsletter Subscribe form.'=>'您的加入申请表是公开的——任何人都可以提交申请，而且一份已提交（并确认）的申请仍会向所有已接纳艺术家和管理员发送邮件。目前，阻挡该表单和自动机器人之间的唯一措施是固定的“每个 IP 每分钟 5 次提交”限制，而分布式机器人可以完全绕过它。在上方添加 Cloudflare Turnstile 站点密钥和密钥，以便在“加入”表单和“订阅通讯”表单上都要求进行人工验证。','OpenAI'=>'OpenAI','Anthropic'=>'Anthropic','AI Processing & Privacy Policy'=>'AI 处理与隐私政策','A Privacy Policy page is set.'=>'已设置隐私政策页面。','Suggested wording covering %s and public federation was added to it automatically — review it under Settings → Privacy → "Guide" before publishing, and check with your provider(s) about their own data processing agreement (DPA) for your compliance obligations.'=>'已自动添加涵盖 %s 和公开联邦的建议措辞——请在发布前于“设置 → 隐私”下的“指南”中查看，并就其自身的数据处理协议（DPA）与您的提供商确认您的合规义务。','No Privacy Policy page is set.'=>'未设置隐私政策页面。','Submitted artwork, text, and visitor contact messages are sent to %s for processing. Create or choose a page under Settings → Privacy — this plugin has already prepared suggested wording you\'ll find there under "Guide". You may also want to review that provider\'s data processing agreement (DPA) for your own compliance obligations.'=>'提交的作品、文本和访客联系消息会发送给 %s 进行处理。请在“设置 → 隐私”下创建或选择一个页面——此插件已在那里准备好建议措辞，您会在“指南”中找到。您也可能需要查看该提供商的数据处理协议（DPA），以满足您自身的合规义务。','Go to Settings → Privacy'=>'前往“设置 → 隐私”','Debug Files'=>'调试文件','Currently'=>'当前','Enabled'=>'已启用','Disabled'=>'已禁用','Forced ON by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'由 wp-config.php 中的 AGNOSIS_DEBUG 常量强制开启——在移除该行之前，上方复选框无效。','Forced OFF by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'由 wp-config.php 中的 AGNOSIS_DEBUG 常量强制关闭——在移除该行之前，上方复选框无效。','Directory'=>'目录','Filter with agnosis_debug_dir to redirect debug output elsewhere.'=>'可通过 agnosis_debug_dir 过滤器将调试输出重定向到其他位置。','.txt file(s) in the directory'=>'目录中的 .txt 文件','Delete all .txt files in the debug directory? The directory itself stays in place so future debug writes still land cleanly.'=>'删除调试目录中的所有 .txt 文件？目录本身将保留，以便未来的调试写入仍能正常落盘。','Clear Debug Files'=>'清除调试文件','Term Translation Cache'=>'术语翻译缓存','Cached translations'=>'已缓存的翻译','AI-translated tag/medium term names, cached so the same term always gets the same translated label instead of a fresh AI phrasing per post. Renaming a term already clears its own cached entry automatically; use the button below only if a cached translation itself is wrong.'=>'由 AI 翻译的标签/媒介术语名称，会被缓存起来，这样同一术语始终使用相同的译名，而不是每篇文章都生成不同的 AI 表述。重命名术语会自动清除其自身的缓存条目；只有当缓存的译文本身有误时，才使用下方按钮。','Clear every cached term translation? Nothing is deleted from your site — terms will simply be re-translated by AI the next time they\'re needed.'=>'清除所有已缓存的术语翻译？不会删除您站点上的任何内容——术语只会在下次需要时由 AI 重新翻译。','Clear Term Translation Cache'=>'清除术语翻译缓存','Pipeline Logs'=>'流水线日志','Clear all log entries?'=>'清除所有日志条目？','Clear All'=>'全部清除','%d entries total. Logs are pruned automatically according to the Inbox retention setting.'=>'共 %d 条记录。日志会根据收件箱保留设置自动清理。','No log entries yet.'=>'尚无日志条目。','Time'=>'时间','Level'=>'级别','Context'=>'上下文','Inbox Tools'=>'收件箱工具','Test connection'=>'测试连接','Test IMAP Connection'=>'测试 IMAP 连接','Connects to the configured mailbox and reports the total and unseen message count.'=>'连接到已配置的邮箱，并报告总消息数和未读消息数。','Poll inbox now'=>'立即轮询收件箱','Poll Inbox Now'=>'立即轮询收件箱','Fetches unseen messages immediately without waiting for WP-Cron. Then click "Process Pending Queue" to run the AI pipeline.'=>'立即获取未读消息，无需等待 WP-Cron。然后点击“处理待处理队列”来运行 AI 流水线。','Process queue'=>'处理队列','Process Pending Queue'=>'处理待处理队列','Immediately runs the AI pipeline on all pending queue items without waiting for WP-Cron. Use this to test the end-to-end flow after a poll.'=>'立即对所有待处理队列项运行 AI 流水线，无需等待 WP-Cron。用于在轮询后测试端到端流程。','Force reprocess'=>'强制重新处理','Force Reprocess Inbox'=>'强制重新处理收件箱','Resets failed/stuck/orphaned queue rows back to pending, then immediately polls for unprocessed messages. Then click "Process Pending Queue" to run the AI pipeline. Already-published artworks with valid posts are never re-processed.'=>'将失败/卡住/孤立的队列行重置回待处理状态，然后立即轮询未处理的消息。然后点击“处理待处理队列”来运行 AI 流水线。已经发布且具有有效文章的作品不会被重新处理。','Deliverability'=>'送达率','A diagnostic check only — nothing here changes how mail is sent. On ordinary hosting (PHP mail(), no SMTP plugin), mail sent from an address that doesn\'t match your site\'s own domain, or from a domain with no SPF/DMARC record at all, is increasingly likely to land in spam or be rejected outright by large mailbox providers. If any row below looks wrong, the most reliable fix is installing an SMTP-sending plugin (WP Mail SMTP, Post SMTP, FluentSMTP, and others all work) configured against a real transactional mail provider, and adding SPF/DMARC records for the domain you send from at your DNS host.'=>'这只是一个诊断检查——这里不会改变邮件发送方式。对于普通主机环境（PHP mail()，没有 SMTP 插件），从与网站自身域名不匹配的地址发送的邮件，或者来自完全没有 SPF/DMARC 记录的域名的邮件，越来越可能被放入垃圾邮件，或被大型邮箱服务商直接拒收。如果下面任一项看起来不对，最可靠的修复方式是安装一个 SMTP 发信插件（WP Mail SMTP、Post SMTP、FluentSMTP 等都可用），并针对你发送邮件所用的域名在 DNS 服务商处添加 SPF/DMARC 记录。','From identity'=>'发件人身份','Domain matches site?'=>'域名与站点匹配？','SPF record'=>'SPF 记录','DMARC record'=>'DMARC 记录','SMTP plugin'=>'SMTP 插件','Detected: %s'=>'检测到：%s','None of the common SMTP-sending plugins were detected — this site is likely relying on PHP\'s built-in mail(), which most hosts deliver poorly through.'=>'未检测到常见的 SMTP 发信插件——此站点很可能依赖 PHP 内置的 mail()，而大多数主机对其邮件投递效果都不佳。','Send a real test email to:'=>'发送一封真实测试邮件到：','Send Test'=>'发送测试邮件','Sends one plain-text email from the same community identity used for review/vote/vouch mail. Reaching your inbox is a good sign; landing in spam or not arriving at all confirms a real deliverability problem regardless of what the checks above say.'=>'从用于审核/投票/担保邮件的同一社区身份发送一封纯文本邮件。若能进入收件箱，说明情况良好；若进入垃圾邮件或根本未送达，则无论上面的检查结果如何，都说明存在真实的送达率问题。','Found'=>'已找到','Not found'=>'未找到','DNS lookup failed'=>'DNS 查询失败','Unavailable on this host'=>'此主机不可用','No address configured'=>'未配置地址','[TEST] Deliverability check from %s'=>'[测试] 来自 %s 的送达率检查','This is a one-off deliverability test from your Agnosis Settings → Email Inbox page. If you\'re reading this in your inbox (not spam), the community/transactional From identity is deliverable to this address.'=>'这是从你的 Agnosis 设置 → 邮箱收件箱 页面发起的一次性送达率测试。如果你在收件箱中看到这封邮件（不是在垃圾邮件里），则说明社区/事务性发件人身份可以投递到此地址。','Pending Applications'=>'待处理申请','%d application is awaiting email confirmation from the applicant and isn\'t listed below yet.'=>'%d 个申请正在等待申请人通过邮件确认，因此尚未列在下面。','No pending applications.'=>'没有待处理的申请。','%d positive vote(s) currently required for admission.'=>'当前需要 %d 个正向投票才能获准加入。','Applicant'=>'申请人','Applied'=>'申请时间','Votes'=>'票数','Bio / Portfolio'=>'简介 / 作品集','%1$d / %2$d'=>'%1$d / %2$d','Portfolio ↗'=>'作品集 ↗','Admit'=>'通过','Reject'=>'拒绝','No admitted members yet.'=>'尚无已接纳成员。','Joined'=>'加入时间','Banned until %s'=>'禁用至 %s','Banned'=>'已封禁','Active'=>'活跃','This address has bounced or been reported as spam — mail may no longer be reaching this artist.'=>'此地址已退信或被举报为垃圾邮件 — 邮件可能已无法送达这位艺术家。','⚠ %d bounce'=>'⚠ %d 次退信','This artist has muted community broadcast messages.'=>'这位艺术家已将社区广播消息设为静音。','🔇 Broadcasts muted'=>'🔇 广播已静音','This artist receives one daily digest of open applications instead of an email per application.'=>'这位艺术家会收到一封每日汇总的未处理申请，而不是每个申请都单独收到一封邮件。','📬 Vote digest mode'=>'📬 投票摘要模式','Leave the date blank to ban indefinitely. Continue?'=>'如需无限期封禁，请将日期留空。继续？','Leave blank to ban indefinitely'=>'留空可无限期封禁','Suspend'=>'暂停','Permanently delete this artist and all their content? This cannot be undone.'=>'永久删除这位艺术家及其所有内容？此操作无法撤销。','Open a community removal vote for this artist? All members will be emailed.'=>'为这位艺术家发起社区移除投票？所有成员都会收到邮件。','Open Vote'=>'发起投票','Newsletter Status'=>'简报状态','You have %1$d confirmed public subscribers, above the configured comfort threshold of %2$d. Self-hosted sending still works, but you may want to connect an email service provider (e.g. Brevo\'s free tier) for better deliverability at this size.'=>'您有 %1$d 位已确认的公开订阅者，超过了配置的舒适阈值 %2$d。自托管发送仍可正常工作，但在这个规模下，您可能希望连接邮件服务提供商（例如 Brevo 的免费套餐）以获得更好的送达率。','Audience'=>'受众','Last sent'=>'上次发送','Action'=>'操作','Failed recipients'=>'发送失败的收件人','Send a test'=>'发送测试','%1$d admitted (%2$d opted out)'=>'已接纳 %1$d 人（%2$d 已选择退出）','Sending…'=>'正在发送…','Idle'=>'空闲','Send Now'=>'立即发送','Public'=>'公开','%1$d confirmed, %2$d pending confirmation, %3$d unsubscribed, %4$d bounced'=>'%1$d 位已确认，%2$d 位待确认，%3$d 位已退订，%4$d 位已退信','By language: %s'=>'按语言：%s','Add the "Newsletter Signup" block to any page to let visitors subscribe to the public newsletter. Artists are enrolled automatically and can unsubscribe from any issue with one click.'=>'在任意页面添加“简报注册”区块，让访客订阅公开简报。艺术家会自动加入，并可通过每期邮件中的一键链接退订。','Never'=>'从不','Unknown'=>'未知','None'=>'无','%d failed'=>'%d 个失败','Retry Failed'=>'重试失败项','Invite an Artist'=>'邀请艺术家','Send a one-off email inviting someone to apply. Nothing is tracked or scheduled — this sends immediately to the address below.'=>'发送一次性邮件邀请他人申请。不会进行跟踪或排期 — 将立即发送到下方地址。','artist@example.com'=>'artist@example.com','Send Invitation'=>'发送邀请','Permission denied.'=>'权限被拒绝。','OpenAI API key not configured.'=>'未配置 OpenAI API 密钥。','OpenAI connection successful.'=>'OpenAI 连接成功。','Anthropic API key not configured.'=>'未配置 Anthropic API 密钥。','Anthropic connection successful.'=>'Anthropic 连接成功。','WordPress AI Client requires WordPress 7.0 or later.'=>'WordPress AI Client 需要 WordPress 7.0 或更高版本。','No text-generation model configured. Set one up under Settings → Connectors.'=>'未配置文本生成模型。请在“设置 → 连接器”下进行设置。','WordPress AI Client is available and a text-generation model is configured.'=>'WordPress AI Client 可用，且已配置文本生成模型。','Unknown provider.'=>'未知提供商。','HTTP %d'=>'HTTP %d','The artist sent no subject line or message with this submission — let the image speak entirely for itself.'=>'这位艺术家在本次提交中没有附上主题或消息——让图片完全自己说话。','Name'=>'名称','Bio'=>'简介','Statement'=>'声明','%1$s must be %2$d characters or fewer.'=>'%1$s 的字符数必须少于或等于 %2$d 个。','Please select your language.'=>'请选择您的语言。','An account with this email address already exists.'=>'使用此电子邮件地址的账户已存在。','This email address belongs to an admitted artist.'=>'此电子邮件地址属于一位已获录取的艺术家。','An application for this email address is already pending.'=>'此电子邮件地址的申请已在等待审核中。','Application not found.'=>'未找到申请。','Only admitted artists can vouch.'=>'只有已获录取的艺术家才能推荐。','Admin access required.'=>'需要管理员权限。','You cannot vote on your own application.'=>'你不能为自己的申请投票。','Invalid or incomplete link.'=>'链接无效或不完整。','This confirmation link is invalid or has already been used.'=>'此确认链接无效或已被使用。','Confirm your application?'=>'确认您的申请？','Your application will open for community review once you confirm below.'=>'在您确认下方内容后，您的申请将开放给社区审核。','Confirm my application'=>'确认我的申请','This community is currently full, so your application has joined the waitlist — when a member leaves, the next person in line is welcomed in.'=>'当前社区已满，因此你的申请已加入等待名单——当有成员离开时，队列中的下一位将被邀请加入。','You\'re all set — the community can now review your application and vote.'=>'一切就绪——社区现在可以审核你的申请并进行投票。','Application confirmed'=>'申请已确认','Thanks, %s!'=>'谢谢，%s！','Link error'=>'链接错误','Confirm your application to %s'=>'确认您加入 %s 的申请','Your application to %s'=>'您提交给 %s 的申请','Application by %s has closed'=>'%s 的申请已结束','Welcome to %s'=>'欢迎来到 %s','We received your application to %s'=>'我们已收到您加入 %s 的申请','Hi %s,'=>'嗨，%s，','One last step before %s can review your application: confirm this is really your email address.'=>'在 %s 审核你的申请之前，还有最后一步：请确认这确实是你的电子邮件地址。','If you didn\'t apply, simply ignore this email — nothing happens until this link is clicked.'=>'如果不是你申请的，请直接忽略这封邮件——在点击此链接之前，不会发生任何事情。','%s — art blooming out of oblivion'=>'%s —— 在遗忘中绽放的艺术','Thank you for applying to %s. Your application has been received and is now open for community review.'=>'感谢您申请加入 %s。您的申请已收到，并现已开放给社区审核。','The community has %d days to vote. We will let you know the outcome by email.'=>'社区有 %d 天的投票时间。我们会通过电子邮件告知您结果。','New application: %1$s wants to join %2$s'=>'新申请：%1$s 想加入 %2$s','%1$s has applied to join %2$s. You have %3$d days to vote.'=>'%1$s 已申请加入 %2$s。你有 %3$d 天进行投票。','Portfolio:'=>'作品集：','Vote YES'=>'投赞成票','Vote NO'=>'投反对票','You can change your vote at any time within the voting window.'=>'你可以在投票期内的任何时候更改你的投票。','Thank you for applying to %s. Unfortunately, your application did not receive enough votes within the voting window.'=>'感谢您申请加入 %s。不幸的是，您的申请未能在投票期内获得足够票数。','You are welcome to apply again in the future.'=>'欢迎您今后再次申请。','The application by %s has closed without reaching the admission threshold. No action required.'=>'%s 的申请在未达到录取门槛的情况下已结束。无需采取任何行动。','The %s community has admitted you as an artist. Welcome!'=>'%s 社区已接纳你为艺术家。欢迎！','Your gallery:'=>'你的画廊：','Your submissions:'=>'你的投稿：','How to share your work — send an email to:'=>'如何分享你的作品——请发送电子邮件至：','Subject line conventions:'=>'主题行约定：','Artwork (default) — any subject'=>'作品（默认）——任意主题','[Biography] — biography update'=>'[Biography] —— 个人简介更新','[Event] — event announcement'=>'[Event] —— 活动公告','[Photo] — publish as-is, no AI enhancement (fallback for mail apps without To: aliases)'=>'[Photo] —— 原样发布，不进行 AI 增强（适用于不支持 To: 别名的邮件客户端的回退方案）','[Pure] — publish exactly as sent, no AI at all (fallback for mail apps without To: aliases)'=>'[Pure] — 按原样发布，不使用任何 AI（适用于不支持 To: 别名的邮件客户端的回退方案）','To leave the network and delete your account:'=>'要退出网络并删除你的账户：','Send any email (no attachment needed). You will receive a confirmation link — nothing is deleted until you click it.'=>'发送任意邮件（无需附件）。你会收到一封确认链接的邮件——在你点击之前，不会删除任何内容。','No login is needed to work with Agnosis — everything above happens by email. If you\'d also like to use the site\'s optional online features (like previewing a submission before it publishes), you can set up a password whenever you like using'=>'使用 Agnosis 不需要登录——以上所有操作都通过邮件完成。如果你还想使用网站的可选在线功能（例如在发布前预览投稿），你可以随时通过设置密码来启用','password recovery'=>'密码找回','Submit artwork'=>'提交作品','Submit biography'=>'提交简介','Submit event'=>'提交活动','Replace artwork (subject: exact title)'=>'替换作品（主题：准确标题）','Remove artwork (subject: exact title)'=>'移除作品（主题：准确标题）','Feature artwork in the shared gallery (subject: exact title)'=>'在共享画廊中推荐作品（主题：准确标题）','Photo-only — publish as-is, no AI enhancement'=>'仅照片——按原样发布，不进行 AI 增强','Pure — publish exactly as sent, no AI at all'=>'Pure——按原样发布，不使用任何 AI','About %s'=>'关于 %s','%1$s — %2$s'=>'%1$s — %2$s','[%s] Your community message was not sent — too long'=>'[%s] 你的社区消息未发送——内容过长','Hi %1$s,

Your message to the community was %2$d characters long — the current limit is %3$d. It was not sent to anyone.

Every recipient\'s copy is translated individually into their own language, so a very long message is costly to translate for the whole community. Please shorten it and send it again.

— %4$s'=>'嗨 %1$s，

你发给社区的消息长度为 %2$d 个字符——当前限制为 %3$d。它没有发送给任何人。

每个接收者的副本都会被单独翻译成他们自己的语言，因此一条很长的消息会给整个社区带来高昂的翻译成本。请将其缩短后再发送一次。

— %4$s','[%s] Your community message was not sent — no content found'=>'[%s] 你的社区消息未发送——未找到内容','Hi %1$s,

Your message to the community had no subject or message text that could be found — this often happens when an email client sends an HTML-only message with no plain-text version included. It was not sent to anyone.

Please try sending it again with plain text included.

— %2$s'=>'嗨 %1$s，

你发给社区的消息没有找到主题或正文文本——这通常发生在邮件客户端只发送 HTML 版本而不包含纯文本版本时。它没有发送给任何人。

请尝试在包含纯文本的情况下再次发送。

— %2$s','[%1$s] Community message from %2$s'=>'[%1$s] 来自 %2$s 的社区消息','%1$s <%2$s> sent a message to the community:'=>'%1$s <%2$s> 向社区发送了一条消息：','Subject: %s'=>'主题：%s','Hit reply to respond — your reply goes back to the whole community, translated automatically, just like this message.'=>'直接回复即可响应——你的回复会回传给整个社区，并像这条消息一样自动翻译。','This message was sent by %s.'=>'此消息由 %s 发送。','%1$s via %2$s'=>'%1$s 经由 %2$s','no limit'=>'无限制','Hi %1$s,

The %2$s community has opened a vote to change the membership size cap to %3$s. The vote closes on %4$s.

A strict majority of active members (more than 50%%) must vote yes for the new cap to be adopted. Sign in to your account to cast your vote.

— %2$s'=>'嗨 %1$s，

%2$s 社区已开启投票，拟将成员规模上限更改为 %3$s。投票将于 %4$s 截止。

必须有活跃成员的严格多数（超过 50%%）投票赞成，新上限才会生效。请登录你的账户投票。

— %2$s','Community size-cap vote open at %s'=>'%s 的社区规模上限投票已开启','Community size cap changed at %s'=>'%s 的社区规模上限已更改','The community voted to change the membership size cap to %1$s (proposal #%2$d). The new cap is now in effect.'=>'社区投票已通过，将成员规模上限更改为 %1$s（提案 #%2$d）。新上限现已生效。','Community size-cap proposal did not pass at %s'=>'%s 的社区规模上限提案未通过','A community vote to change the membership size cap (proposal #%1$d) closed without a majority. The cap is unchanged.'=>'关于更改成员规模上限的社区投票（提案 #%1$d）未获得多数支持而结束。上限保持不变。','Only community members can do this.'=>'只有社区成员才能这样做。','The cap must be zero or a positive number.'=>'上限必须为零或正数。','That is already the current cap.'=>'这已经是当前上限了。','A different cap proposal is already under way. Resolve or co-sign that one first.'=>'另一个上限提案已经在进行中。请先处理或联署那个提案。','No active proposal to co-sign.'=>'没有可联署的有效提案。','Proposal not found.'=>'未找到提案。','This vote is not currently open.'=>'此投票目前未开放。','This artist can\'t be reached through this form right now.'=>'此艺术家目前无法通过此表单联系。','Thanks — your message has been sent.'=>'谢谢——你的消息已发送。','Spam, scams, or unsolicited commercial advertising unrelated to genuinely contacting the artist about their work'=>'垃圾信息、诈骗，或与真正联系艺术家讨论其作品无关的未经请求的商业广告','Flagged by automatic content review.'=>'已被自动内容审核标记。','New message from %s via your Agnosis contact form'=>'来自 %s 的新消息，经由你的 Agnosis 联系表单','From: %s'=>'发件人：%s','(no name provided)'=>'（未提供姓名）','Email: %s'=>'邮箱：%s','Original message, as submitted:'=>'原始消息，按提交内容如下：','Your name (optional)'=>'你的姓名（可选）','Your email address'=>'你的电子邮箱地址','you@example.com'=>'you@example.com','Send message'=>'发送消息','Thanks — your message has been sent. You can reach out to this artist again a little later.'=>'谢谢——您的消息已发送。您稍后还可以再次联系这位艺术家。','Something went wrong. Please try again.'=>'出了点问题。请再试一次。','Authentication required.'=>'需要身份验证。','This field cannot be edited here.'=>'此字段无法在此处编辑。','That date could not be understood.'=>'无法识别该日期。','That does not look like a valid timezone (e.g. "Europe/Madrid").'=>'这看起来不像有效的时区（例如“Europe/Madrid”）。','That does not look like a valid link (must start with http:// or https://).'=>'这看起来不像有效的链接（必须以 http:// 或 https:// 开头）。','The title cannot be empty.'=>'标题不能为空。','Saved — translations will update within a few minutes.'=>'已保存——翻译将在几分钟内更新。','No image file was received.'=>'未收到图片文件。','Please upload a JPEG, PNG, WebP, or GIF image.'=>'请上传 JPEG、PNG、WebP 或 GIF 图片。','The uploaded file could not be read.'=>'无法读取上传的文件。','Untitled'=>'未命名','Photo replaced — the original is kept and can be restored later.'=>'照片已替换——原图会保留，并可在稍后恢复。','There is no photo to restore.'=>'没有可恢复的照片。','No earlier version of this photo was found.'=>'未找到这张照片的更早版本。','Restored the earlier photo.'=>'已恢复较早的照片。','Only admitted artists may edit their own content.'=>'只有被接纳的艺术家才能编辑自己的内容。','Content not found.'=>'未找到内容。','Only published content can be corrected here.'=>'这里只能更正已发布的内容。','You may only edit your own content.'=>'您只能编辑自己的内容。','This page is not in your own language. Edit the version in your language instead.'=>'此页面不是您的语言。请改为编辑您语言的版本。','Unsupported field target.'=>'不支持的字段目标。','Save'=>'保存','Cancel'=>'取消','Saving…'=>'正在保存…','Replace photo'=>'替换照片','Uploading…'=>'正在上传…','Restore earlier photo'=>'恢复较早的照片','Restoring…'=>'正在恢复…','You have left'=>'您已离开','Your account and everything you published on %s have been permanently deleted. Nothing tied to you is stored here anymore.'=>'您在 %s 上的账户以及您发布的一切内容都已被永久删除。这里不再存储任何与您相关的内容。','Link expired or already used'=>'链接已过期或已使用','This confirmation link has already been used or is no longer valid. If you still want to leave, please request removal again from your account.'=>'此确认链接已被使用过，或已不再有效。如果您仍想离开，请从您的账户再次请求删除。','You must be logged in.'=>'您必须登录。','Artist access required.'=>'需要艺术家权限。','No active membership found for this account.'=>'未找到该账户的有效会员资格。','You cannot nominate yourself for removal.'=>'您不能提名自己进行删除。','Artist not found.'=>'未找到艺术家。','Removal request not found.'=>'未找到删除请求。','You cannot vote on your own removal.'=>'您不能对自己的删除进行投票。','Confirm your departure from %s'=>'确认您离开 %s','Hi %1$s,

We received a request to remove your account and all your published work from %2$s.

If you made this request, click the link below to confirm. This action is permanent and cannot be undone.

%3$s

If you did not make this request, you can ignore this email — your account remains unchanged.

— %2$s'=>'嗨，%1$s，

我们收到了从 %2$s 删除您的账户以及您所有已发布作品的请求。

如果这是您提出的请求，请点击下面的链接进行确认。此操作是永久性的，无法撤销。

%3$s

如果这不是您提出的请求，您可以忽略这封邮件——您的账户不会有任何变化。

— %2$s','An artist has left %s'=>'有一位艺术家离开了 %s','%1$s has confirmed their departure from %2$s.

Their account and all published work have been permanently deleted.

— %2$s'=>'%1$s 已确认离开 %2$s。

他们的账户和所有已发布作品已被永久删除。

— %2$s','You\'ve left %s'=>'您已离开 %s','Hi %1$s,

This confirms that your account and everything you published on %2$s have been permanently deleted, as you requested.

Nothing tied to you — your artwork, biography, events, or account details — is stored on %2$s anymore.

If you didn\'t request this, please contact the site admin right away.

— %2$s'=>'嗨，%1$s，

这封邮件确认，按照您的请求，您在 %2$s 上的账户以及您发布的一切内容已被永久删除。

所有与您相关的内容——您的作品、个人简介、活动或账户详情——都不再存储在 %2$s 上。

如果这不是您提出的请求，请立即联系网站管理员。

— %2$s','Hi %1$s,

Your membership at %2$s has been temporarily suspended until %3$s.

You will be automatically reinstated on that date. If you have questions, please contact the site admin.

— %2$s'=>'嗨，%1$s，

您在 %2$s 的会员资格已被暂时停用，直到 %3$s。

您将在该日期自动恢复资格。如果您有任何问题，请联系网站管理员。

— %2$s','Hi %1$s,

Your membership at %2$s has been suspended.

If you have questions, please contact the site admin.

— %2$s'=>'嗨 %1$s，

你在 %2$s 的会员资格已被暂停。

如果你有任何问题，请联系网站管理员。

— %2$s','Your membership at %s has been suspended'=>'你在 %s 的会员资格已被暂停','Hi %1$s,

